result = 0
if contract.employee_id.country_id.code == 'SA':
    insurance_date = contract.employee_id.gosi_registration_date
    contract_start = contract.date_start
    start_day = contract_start.day

    # 1. تحديد تاريخ نهاية الراتب
    c_date = payslip.date_to

    # 2. تحويل التاريخ الحالي إلى أرقام للمقارنة (سنة، شهر، يوم)
    current_tuple = (c_date.year, c_date.month, c_date.day)

    # النسبة الافتراضية
    company_share_percentage = 11.75

    # 3. مقارنة الأرقام مباشرة بالتواريخ المحددة في الجدول
    if current_tuple >= (2028, 7, 3):
        company_share_percentage = 13.75
    elif current_tuple >= (2027, 7, 3):
        company_share_percentage = 13.25
    elif current_tuple >= (2026, 7, 3):
        company_share_percentage = 12.75
    elif current_tuple >= (2025, 7, 3):
        company_share_percentage = 12.25

    daily_cost = ((contract.wage or 0) + (contract.l10n_sa_housing_allowance or 0)) * company_share_percentage / 100 / 30

    year_to_calculate = insurance_date.year if insurance_date else False
    month_to_calculate = insurance_date.month if insurance_date else False

    if not insurance_date:
        result = round(daily_cost * 30)
    elif insurance_date and year_to_calculate == contract_start.year and month_to_calculate == contract_start.month:
        result = round(daily_cost * ((30 - start_day) + 1))
    elif insurance_date and (year_to_calculate > contract_start.year or (year_to_calculate == contract_start.year and month_to_calculate > contract_start.month)):
        if month_to_calculate == contract_start.month and year_to_calculate == contract_start.year:
            days_in_first_month = (30 - start_day) + 1
            result = round(daily_cost * days_in_first_month)
        else:
            result = round(daily_cost * 30)
    else:
        result = 100

    result = abs(result)

total_days = 0
result = 0
dep_name = employee.departure_reason_id.name.lower() if employee.departure_reason_id.name else ''

if "resigned" in dep_name:
    if employee.custom_duration0_due_less_than5 < 720:
        total_days = 0
    else:
        years_service = employee.custom_total0_year0 / 360.0
        if 2 <= years_service < 5:
            total_days += round(employee.amount_of_service_bonus_days / 3)
        elif 5 <= years_service < 10:
            service_bonus_days_first_5 = 75 * (contract.total_salary / 30)
            service_bonus_days_after_5 = employee.amount_of_service_bonus_days - service_bonus_days_first_5
            total_days += round((service_bonus_days_first_5 / 3) + (service_bonus_days_after_5 * 2/3))
        elif years_service >= 10:
            total_days = employee.amount_of_service_bonus_days

if "end of contract" in dep_name:
    total_days += round(employee.amount_of_service_bonus_days)

if dep_name not in ["resigned", "fired", "clause 77", "end of contract"]:
    total_days = 0

if "clause 77" in dep_name:
    total_days = round(employee.amount_of_service_bonus_days)

result = total_days

